import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import Sidebar from '../components/Sidebar';

const Dashboard = () => {
  const { user, logout, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    totalBookings: 5,
    activeRentals: 1,
    totalSpent: 12000,
    completedReturns: 4
  });

  // Redirect if not authenticated
  useEffect(() => {
    if (!isAuthenticated) {
      navigate('/login');
    }
  }, [isAuthenticated, navigate]);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const userName = user?.name || 'Dennis Gresola';

  return (
    <div className="dashboard-page">
      <Sidebar />
      
      <div className="dashboard-content">
        {/* Cards Row */}
        <section className="cards-row" aria-label="Highlights">
          <div className="card" aria-labelledby="currentRentalTitle">
            <h3 id="currentRentalTitle" className="card-title">Current Rental</h3>
            <div className="card-value">
              <img src="https://toyota-website.s3.eu-west-1.amazonaws.com/camry2023.jpg" alt="Toyota Camry" className="card-car-img" />
              Toyota Camry
            </div>
          </div>

          <div className="card" aria-labelledby="nextReservationTitle">
            <h3 id="nextReservationTitle" className="card-title">Next Reservation</h3>
            <div className="card-value">
              <img src="https://www.toyota.com/imgix/responsive/images/mlp/colorizer/2021/wigo/1F7.png" alt="Toyota Wigo" className="card-car-img" />
              Toyota Wigo
            </div>
            <small style={{color: '#555'}}>May 15, 10:00 AM</small>
          </div>

          <div className="card rental-history-card" aria-labelledby="rentalHistoryTitle">
            <h3 id="rentalHistoryTitle" className="card-title">Rental History</h3>
            <div className="rental-history-value" aria-label="Total rentals count">{stats.totalBookings}</div>
          </div>
        </section>

        {/* Rental Details and Upcoming Reservations */}
        <section className="rental-section">
          <div className="rental-details" aria-labelledby="rentalDetailsTitle">
            <div className="rental-details-content">
              <h3 id="rentalDetailsTitle" className="rental-details-title">Rental Details</h3>
              <div className="rental-info">
                <p><strong>Pickup:</strong> April 24, 2026 | 10:00 AM</p>
                <p><strong>Return:</strong> April 28, 2026 | 11:00 AM</p>
                <p><strong>Rental Cost:</strong> Php 12,000.00</p>
                <button type="button" className="manage-btn" aria-label="Manage Rental">Manage Rental</button>
